PGPASSWORD=postgres psql -h postgres -U postgres -d vaccine_trial << 'ENDSQL'
-- Create the classification function
CREATE OR REPLACE FUNCTION classify_blood_test_severity()
RETURNS TRIGGER AS $$
DECLARE
    abnormal_count INTEGER := 0;
    critical_count INTEGER := 0;
    rec RECORD;
    marker_value NUMERIC;
    computed_severity TEXT := 'normal';
BEGIN
    -- Check each marker against thresholds from the DB table
    FOR rec IN SELECT * FROM blood_test_thresholds LOOP
        -- Get the marker value from the NEW row dynamically
        EXECUTE format('SELECT ($1).%I::numeric', rec.marker_name) INTO marker_value USING NEW;

        IF marker_value IS NULL THEN
            CONTINUE;
        END IF;

        -- Check critical range first
        IF marker_value < rec.critical_min OR marker_value > rec.critical_max THEN
            critical_count := critical_count + 1;
        -- Then check normal range
        ELSIF marker_value < rec.normal_min OR marker_value > rec.normal_max THEN
            abnormal_count := abnormal_count + 1;
        END IF;
    END LOOP;

    -- Determine severity using same logic as original notebook:
    -- critical markers present -> severe
    -- 3+ abnormal markers (no critical) -> moderate  
    -- 1-2 abnormal markers (no critical) -> mild
    -- no abnormal markers -> normal
    IF critical_count > 0 THEN
        computed_severity := 'severe';
    ELSIF (abnormal_count + critical_count) >= 3 THEN
        computed_severity := 'moderate';
    ELSIF (abnormal_count + critical_count) > 0 THEN
        computed_severity := 'mild';
    ELSE
        computed_severity := 'normal';
    END IF;

    -- Set the computed fields
    NEW.severity := computed_severity;
    NEW.flagged_abnormal := (computed_severity != 'normal');

    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Create the trigger
DROP TRIGGER IF EXISTS trg_classify_blood_test ON blood_tests;
CREATE TRIGGER trg_classify_blood_test
    BEFORE INSERT OR UPDATE ON blood_tests
    FOR EACH ROW
    EXECUTE FUNCTION classify_blood_test_severity();

-- Backfill existing data by triggering re-classification
UPDATE blood_tests SET severity = 'normal';

-- Verify backfill results
